// Problem 26: Reverse String
// Write a function to reverse a string without using the built-in .reverse() method (use a loop!).
function reverseString(str) {
  let revStr = "";
  for (let i = str.length - 1; i >= 0; i--) {
    revStr += str[i];
  }
  return revStr;
}
console.log("Problem 26:", reverseString("hello")); // Expected: "olleh"

// Problem 27: Palindrome Checker
// Write a function that checks if a string is a palindrome.
function isPalindrome(str) {
  let i = 0;
  let j = str.length - 1;
  let palindrome = true;
  for (; i < j; i++, j--) {
    if (str[i] !== str[j]) {
      palindrome = false;
      break;
    }
  }
  return palindrome;
}
console.log("Problem 27:", isPalindrome("racecar")); // Expected: true

// Problem 28: Remove Duplicates
// Write a function that takes an array with duplicate values and returns a new array with only unique values.
function removeDuplicates(arr) {
  let set = new Set(arr);
  return [...set];
}
console.log("Problem 28:", removeDuplicates([1, 2, 2, 3, 4, 4, 5])); // Expected: [1, 2, 3, 4, 5]

// Problem 29: Flatten Array
// Given a 2D array, flatten it into a 1D array using .reduce().
const nestedArray = [
  [1, 2],
  [3, 4],
  [5, 6],
];
const flatArray = nestedArray.reduce((arr, curr) => {
  arr.push(...curr);
  return arr;
}, []);
console.log("Problem 29:", flatArray); // Expected: [1, 2, 3, 4, 5, 6]

// Problem 30: Group by Property
// Given an array of people objects, use .reduce() to group them into an object by their role.
const people = [
  { name: "Ali", role: "admin" },
  { name: "Sara", role: "user" },
  { name: "Zayed", role: "admin" },
  { name: "Mina", role: "user" },
];
const groupedByRole = people.reduce((obj, curr) => {
  obj[curr.role] = obj[curr.role] ?? [];
  obj[curr.role].push(curr);
  return obj;
}, {});
console.log("Problem 30:", groupedByRole);
// Expected: { admin: [{name: 'Ali', role: 'admin'}, {name: 'Zayed', role: 'admin'}], user: [...] }
